#include "Database.hpp"
#include <bsoncxx/builder/stream/document.hpp>
#include <mongocxx/options/index.hpp>
Database::Database(const std::string& uri, const std::string& database_name) : client_(mongocxx::uri(uri)), database_(client_[database_name]) { ensure_indexes(); }
mongocxx::database Database::database() { return database_; }
void Database::ensure_indexes() { using bsoncxx::builder::stream::document; mongocxx::options::index unique_index; unique_index.unique(true); database_["accounts"].create_index(document{} << "email" << 1 << bsoncxx::builder::stream::finalize, unique_index); database_["accounts"].create_index(document{} << "username" << 1 << bsoncxx::builder::stream::finalize, unique_index); database_["account_roles"].create_index(document{} << "account_id" << 1 << "role" << 1 << bsoncxx::builder::stream::finalize, unique_index); database_["email_verifications"].create_index(document{} << "token" << 1 << bsoncxx::builder::stream::finalize, unique_index); database_["listings"].create_index(document{} << "seller_id" << 1 << bsoncxx::builder::stream::finalize); database_["listing_images"].create_index(document{} << "listing_id" << 1 << "position" << 1 << bsoncxx::builder::stream::finalize, unique_index); database_["chat_participants"].create_index(document{} << "chat_id" << 1 << "account_id" << 1 << bsoncxx::builder::stream::finalize, unique_index); database_["messages"].create_index(document{} << "chat_id" << 1 << "sent_at" << -1 << bsoncxx::builder::stream::finalize); database_["refresh_tokens"].create_index(document{} << "token_hash" << 1 << bsoncxx::builder::stream::finalize, unique_index); }
